// frontend/src/context/RoleContext.js
import React, { createContext, useState, useContext, useEffect, useCallback } from 'react';
import api from '../services/api';

const RoleContext = createContext();

export const useRole = () => {
    const context = useContext(RoleContext);
    if (!context) {
        throw new Error('useRole must be used within RoleProvider');
    }
    return context;
};

export const RoleProvider = ({ children }) => {
    const [userRole, setUserRole] = useState(null);
    const [permissions, setPermissions] = useState([]);
    const [loading, setLoading] = useState(true);

    const fetchPermissions = useCallback(async () => {
        // Check if user is logged in by looking for token
        const token = localStorage.getItem('authToken');
        if (!token) {
            console.log('No token found, skipping permissions fetch');
            setLoading(false);
            return;
        }

        try {
            const response = await api.get('/roles/my/permissions');
            setUserRole(response.data.role);
            setPermissions(response.data.permissions);
        } catch (error) {
            console.error('Failed to fetch permissions:', error);
            // If 401, user is not authenticated
            if (error.response?.status === 401) {
                console.log('User not authenticated, clearing permissions');
                setUserRole(null);
                setPermissions([]);
            }
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchPermissions();
    }, [fetchPermissions]);

    // Listen for login/logout events to refetch permissions
    useEffect(() => {
        const handleStorageChange = () => {
            fetchPermissions();
        };
        
        window.addEventListener('storage', handleStorageChange);
        
        return () => {
            window.removeEventListener('storage', handleStorageChange);
        };
    }, [fetchPermissions]);

    const hasPermission = useCallback((permission) => {
        return permissions.includes(permission);
    }, [permissions]);

    const hasAnyPermission = useCallback((permissionList) => {
        return permissionList.some(p => permissions.includes(p));
    }, [permissions]);

    const hasAllPermissions = useCallback((permissionList) => {
        return permissionList.every(p => permissions.includes(p));
    }, [permissions]);

    const isRole = useCallback((role) => {
        return userRole === role;
    }, [userRole]);

    const isAnyRole = useCallback((roleList) => {
        return roleList.includes(userRole);
    }, [userRole]);

    const value = {
        userRole,
        permissions,
        loading,
        hasPermission,
        hasAnyPermission,
        hasAllPermissions,
        isRole,
        isAnyRole,
        refresh: fetchPermissions
    };

    return <RoleContext.Provider value={value}>{children}</RoleContext.Provider>;
};
